import{_ as e,o as t,c as a,ai as r}from"./chunks/framework.BIXs0jTs.js";const i="/assets/preface-cover.Balx8Fq4.png",h=JSON.parse('{"title":"附录 A：Prompt 模板索引","description":"","frontmatter":{"title":"附录 A：Prompt 模板索引","outline":"deep"},"headers":[],"relativePath":"90-appendix/prompt-index.md","filePath":"90-appendix/prompt-index.md","lastUpdated":null}'),d={name:"90-appendix/prompt-index.md"};function c(n,o,l,p,s,m){return t(),a("div",null,[...o[0]||(o[0]=[r('<h1 id="附录-a-prompt-模板索引" tabindex="-1">附录 A　Prompt 模板索引 <a class="header-anchor" href="#附录-a-prompt-模板索引" aria-label="Permalink to &quot;附录 A　Prompt 模板索引&quot;">​</a></h1><p><img src="'+i+'" alt="附录：Prompt 模板索引与参考"></p><p>本附录整理了书中各章节提到的关键 Prompt，以及在实际开发中经过验证的高效指令。你可以直接复制这些 Prompt，根据你的项目上下文稍作修改即可使用。</p><h2 id="a-1-claude-code-基础-prompt" tabindex="-1">A.1 Claude Code 基础 Prompt <a class="header-anchor" href="#a-1-claude-code-基础-prompt" aria-label="Permalink to &quot;A.1 Claude Code 基础 Prompt&quot;">​</a></h2><h3 id="项目初始化-project-initialization" tabindex="-1">项目初始化 (Project Initialization) <a class="header-anchor" href="#项目初始化-project-initialization" aria-label="Permalink to &quot;项目初始化 (Project Initialization)&quot;">​</a></h3><p>用于快速搭建项目骨架。</p><blockquote><p><strong>Prompt</strong>: &quot;请使用 [技术栈，例如 Vite + React + TypeScript] 初始化一个名为 [项目名称] 的新项目。安装 [关键依赖，例如 Tailwind CSS, Zustand] 并配置好基础样式。请确保项目结构符合最佳实践。&quot;</p></blockquote><h3 id="代码解释-code-explanation" tabindex="-1">代码解释 (Code Explanation) <a class="header-anchor" href="#代码解释-code-explanation" aria-label="Permalink to &quot;代码解释 (Code Explanation)&quot;">​</a></h3><p>用于理解复杂的遗留代码。</p><blockquote><p><strong>Prompt</strong>: &quot;请阅读 <code>[文件路径]</code>。解释 <code>[函数名或类名]</code> 的核心逻辑。请使用 Mermaid 绘制其时序图，展示数据流向。如果是你来重构这段代码，你会怎么做？&quot;</p></blockquote><h3 id="单元测试生成-test-generation" tabindex="-1">单元测试生成 (Test Generation) <a class="header-anchor" href="#单元测试生成-test-generation" aria-label="Permalink to &quot;单元测试生成 (Test Generation)&quot;">​</a></h3><p>用于为现有代码补充测试。</p><blockquote><p><strong>Prompt</strong>: &quot;请为 <code>[文件路径]</code> 中的 <code>[函数名]</code> 编写单元测试。使用 [测试框架，例如 Vitest]。请覆盖正常情况、边界情况（如空输入、极大值）以及异常处理路径。不要修改原代码，只生成测试文件。&quot;</p></blockquote><h3 id="提交信息生成-commit-message" tabindex="-1">提交信息生成 (Commit Message) <a class="header-anchor" href="#提交信息生成-commit-message" aria-label="Permalink to &quot;提交信息生成 (Commit Message)&quot;">​</a></h3><p>用于生成规范的 Git 提交信息。</p><blockquote><p><strong>Prompt</strong>: &quot;请分析我刚才的修改（运行 <code>git diff</code>）。生成一条符合 Conventional Commits 规范的提交信息。格式应为：<code>&lt;type&gt;(&lt;scope&gt;): &lt;subject&gt;</code>，并包含详细的 Body 解释修改原因。&quot;</p></blockquote><h2 id="a-2-skill-设计-prompt" tabindex="-1">A.2 Skill 设计 Prompt <a class="header-anchor" href="#a-2-skill-设计-prompt" aria-label="Permalink to &quot;A.2 Skill 设计 Prompt&quot;">​</a></h2><h3 id="skill-定义生成-skill-definition" tabindex="-1">Skill 定义生成 (Skill Definition) <a class="header-anchor" href="#skill-定义生成-skill-definition" aria-label="Permalink to &quot;Skill 定义生成 (Skill Definition)&quot;">​</a></h3><p>用于让 Claude 帮你写 <code>CLAUDE.md</code> 中的 Skill 定义。</p><blockquote><p><strong>Prompt</strong>: &quot;我想创建一个名为 <code>[Skill 名称]</code> 的 Skill，它的功能是 <code>[功能描述]</code>。它需要接受 <code>[参数列表]</code> 作为输入。请为我生成对应的 <code>CLAUDE.md</code> 配置代码，包括 <code>description</code> 和 <code>cmd</code> 字段。&quot;</p></blockquote><h3 id="复杂命令封装-command-wrapping" tabindex="-1">复杂命令封装 (Command Wrapping) <a class="header-anchor" href="#复杂命令封装-command-wrapping" aria-label="Permalink to &quot;复杂命令封装 (Command Wrapping)&quot;">​</a></h3><p>用于将复杂的 Shell 命令封装为 Skill。</p><blockquote><p><strong>Prompt</strong>: &quot;请将以下命令封装为一个名为 <code>deploy-prod</code> 的 Skill：<code>[复杂命令，例如 ./deploy.sh --env=prod --key=$KEY]</code>。请确保它能从环境变量中读取密钥，并且在执行前要求用户确认。&quot;</p></blockquote><h2 id="a-3-mcp-开发-prompt" tabindex="-1">A.3 MCP 开发 Prompt <a class="header-anchor" href="#a-3-mcp-开发-prompt" aria-label="Permalink to &quot;A.3 MCP 开发 Prompt&quot;">​</a></h2><h3 id="mcp-server-脚手架-server-scaffolding" tabindex="-1">MCP Server 脚手架 (Server Scaffolding) <a class="header-anchor" href="#mcp-server-脚手架-server-scaffolding" aria-label="Permalink to &quot;MCP Server 脚手架 (Server Scaffolding)&quot;">​</a></h3><p>用于快速创建 MCP Server。</p><blockquote><p><strong>Prompt</strong>: &quot;请使用 TypeScript 和 <code>@modelcontextprotocol/sdk</code> 创建一个 MCP Server。它应该包含一个名为 <code>[工具名]</code> 的 Tool，用于 <code>[工具功能]</code>。请生成 <code>index.ts</code>、<code>package.json</code> 和 <code>tsconfig.json</code>。&quot;</p></blockquote><h3 id="sql-查询生成-sql-generation-via-mcp" tabindex="-1">SQL 查询生成 (SQL Generation via MCP) <a class="header-anchor" href="#sql-查询生成-sql-generation-via-mcp" aria-label="Permalink to &quot;SQL 查询生成 (SQL Generation via MCP)&quot;">​</a></h3><p>用于通过 <code>sqlite</code> MCP Server 查询数据。</p><blockquote><p><strong>Prompt</strong>: &quot;请连接到 <code>[数据库路径]</code>。查询 <code>[表名]</code> 表，找出 <code>[条件，例如最近 7 天注册的用户]</code>。请按 <code>[字段]</code> 排序并只返回前 10 条。请先告诉我你要执行的 SQL，再执行。&quot;</p></blockquote><h3 id="api-适配器生成-api-adapter" tabindex="-1">API 适配器生成 (API Adapter) <a class="header-anchor" href="#api-适配器生成-api-adapter" aria-label="Permalink to &quot;API 适配器生成 (API Adapter)&quot;">​</a></h3><p>用于将外部 API 转换为 MCP Tool。</p><blockquote><p><strong>Prompt</strong>: &quot;请阅读 <code>[OpenAPI 文档 URL]</code>。为其中的 <code>[API 路径]</code> 端点创建一个 MCP Tool 定义。请提取所有必需参数，并为每个参数添加详细的描述，以便 LLM 理解。&quot;</p></blockquote><h2 id="a-4-团队协作-prompt" tabindex="-1">A.4 团队协作 Prompt <a class="header-anchor" href="#a-4-团队协作-prompt" aria-label="Permalink to &quot;A.4 团队协作 Prompt&quot;">​</a></h2><h3 id="代码审查-code-review" tabindex="-1">代码审查 (Code Review) <a class="header-anchor" href="#代码审查-code-review" aria-label="Permalink to &quot;代码审查 (Code Review)&quot;">​</a></h3><p>用于让 Claude 扮演审查者。</p><blockquote><p><strong>Prompt</strong>: &quot;请作为一名资深 [语言] 工程师审查 <code>[文件路径]</code>。关注以下几点：1. 安全性（是否存在注入风险）；2. 性能（是否有不必要的循环）；3. 可读性（命名是否规范）。请以列表形式给出具体的修改建议。&quot;</p></blockquote><h3 id="文档生成-documentation" tabindex="-1">文档生成 (Documentation) <a class="header-anchor" href="#文档生成-documentation" aria-label="Permalink to &quot;文档生成 (Documentation)&quot;">​</a></h3><p>用于生成项目文档。</p><blockquote><p><strong>Prompt</strong>: &quot;请阅读当前目录下的所有代码。生成一份 <code>README.md</code>，包含：项目简介、安装步骤、核心功能列表、配置说明。请使用 Markdown 格式，并包含适当的代码块示例。&quot;</p></blockquote><h3 id="架构决策记录-adr-generation" tabindex="-1">架构决策记录 (ADR Generation) <a class="header-anchor" href="#架构决策记录-adr-generation" aria-label="Permalink to &quot;架构决策记录 (ADR Generation)&quot;">​</a></h3><p>用于记录技术决策。</p><blockquote><p><strong>Prompt</strong>: &quot;我们刚才决定使用 <code>[技术 A]</code> 而不是 <code>[技术 B]</code> 来实现 <code>[功能]</code>。请帮我撰写一份 ADR (Architecture Decision Record)，记录背景、选择理由、被否决的方案以及潜在的后果。&quot;</p></blockquote>',43)])])}const q=e(d,[["render",c]]);export{h as __pageData,q as default};
